import{_ as r,o as s,c as t,a2 as n}from"./chunks/framework.D2pTuMig.js";const f=JSON.parse('{"title":"Découvrir getinside - Plateforme Retail Media","description":"Découvrez comment getinside monétise vos colis et emails tout en finançant votre acquisition. La plateforme retail media pour annonceurs et e-commerçants.","frontmatter":{"title":"Découvrir getinside - Plateforme Retail Media","description":"Découvrez comment getinside monétise vos colis et emails tout en finançant votre acquisition. La plateforme retail media pour annonceurs et e-commerçants.","keywords":["retail media","monétisation","colis","email marketing","e-commerce","plateforme publicitaire","getinside"],"image":"/images/gi-keyvisual.svg"},"headers":[],"relativePath":"docs/fr/start-here/index.md","filePath":"docs/fr/start-here/index.md"}'),a={name:"docs/fr/start-here/index.md"};function i(o,e,l,c,u,d){return s(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="transformez-vos-audiences-en-chiffre-d-affaires" tabindex="-1">Transformez vos audiences en chiffre d&#39;affaires <a class="header-anchor" href="#transformez-vos-audiences-en-chiffre-d-affaires" aria-label="Permalink to &quot;Transformez vos audiences en chiffre d&#39;affaires&quot;">​</a></h1><p>Rejoignez <strong>+250 e-commerçants</strong> et <strong>+300 annonceurs</strong> qui utilisent getinside pour monétiser directement leurs audiences. <strong>+950 campagnes</strong> opérées avec succès.</p><p><img src="/images/gi-keyvisual.svg" alt="getinside - Plateforme Retail Media"></p><hr><h2 id="les-4-piliers-de-getinside" tabindex="-1">Les 4 Piliers de getinside <a class="header-anchor" href="#les-4-piliers-de-getinside" aria-label="Permalink to &quot;Les 4 Piliers de getinside&quot;">​</a></h2><h3 id="🎯-pour-les-annonceurs-performance-confiance" tabindex="-1">🎯 Pour les Annonceurs : Performance &amp; Confiance <a class="header-anchor" href="#🎯-pour-les-annonceurs-performance-confiance" aria-label="Permalink to &quot;🎯 Pour les Annonceurs : Performance &amp; Confiance&quot;">​</a></h3><p><strong>100% de taux d&#39;ouverture</strong> sur l&#39;insertion colis grâce à l&#39;hyper-attention du déballage. <strong>1-10% de CTR</strong> et <strong>10-30% de conversion</strong> post-scan — les performances les plus élevées du marché.</p><p>Diversifiez vos canaux d&#39;acquisition face à la saturation de Google et Meta. Bénéficiez de la confiance (Endorsement) de l&#39;e-commerçant envers sa communauté.</p><p><a href="/handbook/docs/fr/advertisers/">Accéder à l&#39;espace Annonceurs →</a></p><hr><h3 id="📦-pour-les-retailers-revenus-controle" tabindex="-1">📦 Pour les Retailers : Revenus &amp; Contrôle <a class="header-anchor" href="#📦-pour-les-retailers-revenus-controle" aria-label="Permalink to &quot;📦 Pour les Retailers : Revenus &amp; Contrôle&quot;">​</a></h3><p><strong>+2% à +20% de chiffre d&#39;affaires additionnel</strong> composé quasi-intégralement de <strong>marge nette 65-70%</strong>.</p><p>Générez des revenus sans effort tout en gardant un contrôle absolu sur les marques que vous acceptez de diffuser à vos clients. Aucune intégration technique lourde.</p><p><a href="/handbook/docs/fr/publishers/">Accéder à l&#39;espace Retailers →</a></p><hr><h3 id="🔄-le-modele-smart-funding-cercle-vertueux" tabindex="-1">🔄 Le Modèle Smart Funding : Cercle Vertueux <a class="header-anchor" href="#🔄-le-modele-smart-funding-cercle-vertueux" aria-label="Permalink to &quot;🔄 Le Modèle Smart Funding : Cercle Vertueux&quot;">​</a></h3><p>Transformez vos <strong>centres de coûts</strong> (colis, emails) en <strong>centres de profits</strong>, et réinvestissez les gains immédiatement pour financer votre propre acquisition client <strong>sans sortir de trésorerie</strong>.</p><p><strong>3 étapes :</strong></p><ol><li><strong>Gagnez</strong> : Monétisez vos colis et emails</li><li><strong>Financez</strong> : Utilisez ce solde (Wallet) immédiatement</li><li><strong>Croissez</strong> : Achetez du trafic qualifié pour votre propre site</li></ol><hr><h3 id="🛡️-le-tiers-de-confiance-un-seul-contrat-tout-securise" tabindex="-1">🛡️ Le Tiers de Confiance : Un Seul Contrat, Tout Sécurisé <a class="header-anchor" href="#🛡️-le-tiers-de-confiance-un-seul-contrat-tout-securise" aria-label="Permalink to &quot;🛡️ Le Tiers de Confiance : Un Seul Contrat, Tout Sécurisé&quot;">​</a></h3><p>Un seul contrat, une seule facturation, et des paiements garantis et sécurisés.</p><p>getinside centralise l&#39;écosystème complet : intégration tech, impression, routage, tracking, RGPD. <strong>Fini la gestion complexe.</strong></p><hr><div class="info custom-block"><p class="custom-block-title">Prêt à démarrer ?</p><ul><li><strong>Annonceur</strong> : Touchez vos futurs clients via des audiences hautement qualifiées</li><li><strong>Retailer</strong> : Transformez vos colis en chiffre d&#39;affaires additionnel</li></ul><p><a href="mailto:studio@getinside.com" target="_blank" rel="noreferrer">Discuter de mon projet →</a></p></div>',25)])])}const p=r(a,[["render",i]]);export{f as __pageData,p as default};
